"use client"

import ConnectButton from '@pages/home/ConnectButton'
import React, { useEffect, useMemo, useState } from 'react'
import { connection } from '@api/Connection';
import { progressEvents } from "@api/ProgressEvents"
import { useRouter } from 'next/navigation';
import { EventAction } from "@api/ProgressEvents";
import GShockAPI from '@/api/GShockAPI';
import { PhoneFinder } from './home/PhoneFinder';

import Typography from '@mui/material/Typography';
import {
  Box, List, ListItem, ListItemIcon, ListItemText,
  Divider, Paper, useTheme, Dialog, DialogTitle,
  DialogContent, DialogActions, Button, alpha
} from '@mui/material';
import BluetoothIcon from '@mui/icons-material/Bluetooth';
import WatchIcon from '@mui/icons-material/Watch';
import AccessTimeIcon from '@mui/icons-material/AccessTime';
import InfoIcon from '@mui/icons-material/Info';

// Import local images directly based on project structure
import dw_b5600 from '../../images/dw-b5600.png';
import ecb_30d from '../../images/ecb_30d.png';
import ga_b2100 from '../../images/ga_b2100.png';
import gw_b5600 from '../../images/gw_b5600.png';

const BOTTOM_NAV_HEIGHT = '80px';

function Home() {
  const router = useRouter();
  const theme = useTheme();
  const [isBluetoothSupported, setIsBluetoothSupported] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);

  const navigateToTimePage = useMemo(() => () => router.push('/time/Time'), [router]);
  const navigateToHomePage = useMemo(() => () => router.push('/'), [router]);

  const handleWatchConnectedAndInit = useMemo(() => async () => {
    if (GShockAPI.isFindPhoneButtonPressed()) {
      const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);
      if (isMobile) {
        PhoneFinder.ring();
      }
    } else if (GShockAPI.isActionButtonPressed() || GShockAPI.isAutoTimeStarted()) {
      await GShockAPI.setTime();
      // Stay on home screen to represent headless sync
    } else {
      navigateToTimePage();
    }
  }, [navigateToTimePage]);

  const actions: EventAction[] = useMemo(() => [
    { label: "Disconnected", action: navigateToHomePage },
    { label: "WatchInitializationCompleted", action: handleWatchConnectedAndInit },
  ], [navigateToHomePage, handleWatchConnectedAndInit]);

  useEffect(() => {
    if (!navigator.bluetooth) {
      setIsBluetoothSupported(false);
      setDialogOpen(true);
    }
  }, []);

  useEffect(() => {
    progressEvents.runEventActions("Home", actions);
  }, [actions]);

  // Handle explicit component mounts when watch is already initialized
  useEffect(() => {
    // If it's already connected AND initialized, we fall back to normal button logic if they reload Home
    if (connection.isConnected()) {
      if (GShockAPI.isNormalButtonPressed()) navigateToTimePage();
    }
  }, [navigateToTimePage]);

  const handleCloseDialog = () => setDialogOpen(false);

  return (
    <Box sx={{
      display: 'flex',
      flexDirection: 'column',
      // '100%' ensures it fits inside your desktop layout's main container, 
      // while '100dvh' fallback ensures mobile height is correct.
      height: { xs: '100dvh', md: '100%' },
      width: '100%',
      overflow: 'hidden',
      bgcolor: 'background.default',
      position: 'relative'
    }}>

      {/* 1. SCROLLABLE CONTENT */}
      <Box sx={{
        flex: 1,
        overflowY: 'auto',
        WebkitOverflowScrolling: 'touch',
        px: { xs: 2, sm: 4, md: 6 },
        pt: { xs: 2, md: 4 },
        pb: 2
      }}>

        <Typography
          variant="h5"
          sx={{ fontWeight: 800, color: 'primary.main', mb: 3, textAlign: 'center' }}
        >
          Get Started
        </Typography>

        {/* Watch Images Row */}
        <Box sx={{ 
          display: 'flex', 
          justifyContent: 'center', 
          gap: { xs: 2, sm: 3 }, 
          mb: 4, 
          flexWrap: 'wrap' 
        }}>
          {[dw_b5600, ecb_30d, ga_b2100, gw_b5600].map((imgSrc, index) => (
            <Box 
              key={index}
              sx={{ 
                height: { xs: 80, sm: 100, md: 120 }, // Small enough to not push connect button down too far
                display: 'flex'
              }} 
            >
              <img
                src={typeof imgSrc === 'string' ? imgSrc : imgSrc.src as string} 
                alt="Supported Watch"
                style={{ height: '100%', objectFit: 'contain' }}
              />
            </Box>
          ))}
        </Box>

        <Box sx={{ maxWidth: 600, mx: 'auto' }}>
          <List sx={{ '& .MuiListItem-root': { mb: 2 } }}>
            <ListItem disableGutters>
              <ListItemIcon sx={{ minWidth: 40 }}>
                <BluetoothIcon color="primary" />
              </ListItemIcon>
              <ListItemText
                primary={<Typography variant="subtitle1" sx={{ fontWeight: 700 }}>Pair Your Watch</Typography>}
                secondary="Click the button at the bottom to start searching."
              />
            </ListItem>

            <ListItem disableGutters>
              <ListItemIcon sx={{ minWidth: 40 }}>
                <WatchIcon color="primary" />
              </ListItemIcon>
              <ListItemText
                primary={<Typography variant="subtitle1" sx={{ fontWeight: 700 }}>Watch Mode</Typography>}
                secondary="Hold the LOWER-LEFT button on your G-Shock until it beeps."
              />
            </ListItem>

            <ListItem disableGutters>
              <ListItemIcon sx={{ minWidth: 40 }}>
                <AccessTimeIcon color="primary" />
              </ListItemIcon>
              <ListItemText
                primary={<Typography variant="subtitle1" sx={{ fontWeight: 700 }}>Configuration</Typography>}
                secondary="Set the time, timer, and alarms instantly."
              />
            </ListItem>
          </List>

          <Divider sx={{ my: 3 }} />

          <Paper elevation={0} sx={{
            p: 2,
            bgcolor: alpha(theme.palette.info.main, 0.08),
            borderRadius: 3,
            border: `1px solid ${alpha(theme.palette.info.main, 0.2)}`
          }}>
            <Box sx={{ display: 'flex', gap: 2 }}>
              <InfoIcon color="info" />
              <Box>
                <Typography variant="body2" sx={{ fontWeight: 700, mb: 0.5 }}>
                  Bluetooth Connection
                </Typography>
                <Typography variant="caption" color="text.secondary">
                  If pairing fails, ensure your browser has Bluetooth permissions enabled and no other app is currently connected to the watch.
                </Typography>
              </Box>
            </Box>
          </Paper>
        </Box>
      </Box>

      {/* 2. RESPONSIVE ACTION AREA */}
      <Box sx={{
        p: 2,
        borderTop: `1px solid ${theme.palette.divider}`,
        bgcolor: 'background.paper',
        zIndex: 10,
        // On mobile (xs), add margin to sit above bottom nav. 
        // On desktop (md), remove margin and add subtle centering.
        mb: { xs: BOTTOM_NAV_HEIGHT, md: 0 },
        pb: { xs: `calc(env(safe-area-inset-bottom) + 8px)`, md: 2 },
        display: 'flex',
        justifyContent: 'center'
      }}>
        <Box sx={{ width: '100%', maxWidth: 400 }}>
          <ConnectButton />
        </Box>
      </Box>

      {/* Browser Support Dialog */}
      <Dialog open={dialogOpen} onClose={handleCloseDialog} fullWidth maxWidth="xs">
        <DialogTitle sx={{ fontWeight: 700 }}>Incompatible Browser</DialogTitle>
        <DialogContent>
          <Typography variant="body2" color="text.secondary">
            Web Bluetooth is required. Please use Chrome, Edge, or Bluefy on iOS.
          </Typography>
        </DialogContent>
        <DialogActions sx={{ p: 2 }}>
          <Button onClick={handleCloseDialog} variant="outlined" fullWidth>
            I Understand
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  )
}

export default Home;

"use client"

import React, { useEffect, useState } from 'react';
import {
    Dialog,
    DialogTitle,
    DialogContent,
    DialogActions,
    Box,
    TextField,
    FormControl,
    InputLabel,
    Select,
    MenuItem,
    RadioGroup,
    FormControlLabel,
    Radio,
    FormGroup,
    Checkbox,
    FormHelperText,
    Button,
    Typography,
    Divider
} from '@mui/material';
import { LocalizationProvider } from '@mui/x-date-pickers/LocalizationProvider';
import { DatePicker } from '@mui/x-date-pickers/DatePicker';
import { AdapterDayjs } from '@mui/x-date-pickers/AdapterDayjs';
import ReminderData, { dayOfWeekType, monthType, repeatPeriodType } from './ReminderData';
import { fromDayJsDate, toDayJsDate } from './ReminderUtils';
import { Dayjs } from 'dayjs';
import dayjs from 'dayjs';

interface ReminderEditDialogProps {
    open: boolean;
    handleClose: (returnData: any) => void;
    startDate: Dayjs;
    initReminderData: ReminderData;
}

type frequencyDisplayType = "Does not repeat" | "Daily" | "Weekly" | "Monthly" | "Yearly";

const ReminderEditDialog: React.FC<ReminderEditDialogProps> = ({ open, handleClose, startDate, initReminderData }) => {

    const [endOnIndex, setOnIndex] = useState(0);
    const [repeatEventsVisible, setRepeatEventsVisible] = useState(false);
    const [weeklyEventsVisible, setWeeklyEventsVisible] = useState(false);
    const [endDate, setEndDate] = useState(initReminderData.endDate ? toDayJsDate(initReminderData.endDate) : startDate);
    const [currentStartDate, setCurrentStartDate] = useState(startDate);
    const [error, setError] = useState({ state: false, message: "" });
    const [frequency, setFrequency] = useState(initReminderData.repeatPeriod);
    const [reminderData, setReminderData] = useState<ReminderData>(initReminderData);
    const [title, setTitle] = useState(initReminderData.title);

    const configureDialog = (data: ReminderData) => {
        const start = toDayJsDate(data.startDate);
        const end = data.endDate ? toDayJsDate(data.endDate) : start;

        setCurrentStartDate(start);
        setEndDate(end);

        if (data.occurrences > 0) {
            setOnIndex(2);
        } else if (data.endDate && !end.isSame(start)) {
            setOnIndex(1);
        } else {
            setOnIndex(0);
        }

        if (data.repeatPeriod !== "NEVER") { 
            setRepeatEventsVisible(true) 
        } else { 
            setRepeatEventsVisible(false) 
        }

        if (data.repeatPeriod === "WEEKLY") { 
            setWeeklyEventsVisible(true) 
        } else { 
            setWeeklyEventsVisible(false) 
        }

        setFrequency(data.repeatPeriod);
    }

    useEffect(() => {
        setReminderData(initReminderData);
        setTitle(initReminderData.title);
        configureDialog(initReminderData);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [initReminderData]);

    const checkBoxes = [
        { value: "MONDAY", displayValue: "Mon" },
        { value: "TUESDAY", displayValue: "Tue" },
        { value: "WEDNESDAY", displayValue: "Wed" },
        { value: "THURSDAY", displayValue: "Thu" },
        { value: "FRIDAY", displayValue: "Fri" },
        { value: "SATURDAY", displayValue: "Sat" },
        { value: "SUNDAY", displayValue: "Sun" }
    ]

    const handleSelectFrequency = (displayValue: frequencyDisplayType) => {
        const freq = getRepeatPeriodType(displayValue)
        setFrequency(freq);

        if (freq !== "NEVER") { setRepeatEventsVisible(true) } else { setRepeatEventsVisible(false) }
        if (freq === "WEEKLY") { setWeeklyEventsVisible(true) } else { setWeeklyEventsVisible(false) }

        setReminderData({
            ...reminderData,
            repeatPeriod: freq,
        })
    }

    const handleEndOnChange = (index: number) => {
        setOnIndex(index);
    }

    const handleOccurrencesChange = (value: string) => {
        const num = parseInt(value, 10);
        if (!isNaN(num) && num > 0) {
            setReminderData({
                ...reminderData,
                occurrences: num,
                endDate: { year: startDate.year(), month: startDate.format("MMMM") as monthType, day: startDate.date() }
            });
            setError({ state: false, message: "" })
        } else {
            setReminderData({ ...reminderData, occurrences: 0 });
            setError({ state: true, message: "Please enter a number greater than 0" })
        }
    }

    const handleDaysOfWeekChange = (day: string, checked: boolean) => {
        if (checked) {
            setReminderData({ ...reminderData, daysOfWeek: [...reminderData.daysOfWeek, day as dayOfWeekType] });
        } else {
            setReminderData({ ...reminderData, daysOfWeek: reminderData.daysOfWeek.filter(d => d !== day) });
        }
    }

    const handleSave = () => {
        const data = {
            ...reminderData,
            title: title || "No Title",
            endDate: reminderData.endDate || reminderData.startDate
        };
        handleClose(data);
    }

    return (
        <Dialog open={open} onClose={() => handleClose(reminderData)} fullWidth maxWidth="sm">
            <DialogTitle>Edit Event</DialogTitle>
            <DialogContent sx={{ pt: 2 }}>
                <Box sx={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
                    <TextField
                        fullWidth
                        label="Title"
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                        variant="outlined"
                    />

                    <FormControl fullWidth>
                        <InputLabel>Frequency</InputLabel>
                        <Select
                            value={forDisplay(frequency)}
                            label="Frequency"
                            onChange={(e) => handleSelectFrequency(e.target.value as frequencyDisplayType)}
                        >
                            {frequencyDisplayOptions.map((option) => (
                                <MenuItem key={option} value={option}>
                                    {option}
                                </MenuItem>
                            ))}
                        </Select>
                    </FormControl>

                    <LocalizationProvider dateAdapter={AdapterDayjs}>
                        <DatePicker
                            label="Start Date"
                            value={currentStartDate}
                            onChange={(newDate) => {
                                if (newDate) {
                                    setCurrentStartDate(newDate);
                                    setReminderData({
                                        ...reminderData,
                                        startDate: fromDayJsDate(newDate),
                                        endDate: reminderData.endDate || { year: newDate.year(), month: newDate.format("MMMM") as monthType, day: newDate.date() }
                                    });
                                }
                            }}
                            slotProps={{
                                textField: { fullWidth: true }
                            }}
                        />
                    </LocalizationProvider>

                    {repeatEventsVisible && (
                        <Box sx={{ border: '1px solid', borderColor: 'divider', borderRadius: 1, p: 2 }}>
                            <Typography variant="subtitle2" sx={{ fontWeight: 600, mb: 2 }}>
                                Ends on
                            </Typography>
                            <RadioGroup
                                value={endOnIndex.toString()}
                                onChange={(e) => handleEndOnChange(parseInt(e.target.value))}
                            >
                                <FormControlLabel
                                    value="0"
                                    control={<Radio />}
                                    label="Never"
                                />
                                <FormControlLabel
                                    value="1"
                                    control={<Radio />}
                                    label="On a specific date"
                                />
                                <FormControlLabel
                                    value="2"
                                    control={<Radio />}
                                    label="After a number of occurrences"
                                />
                            </RadioGroup>

                            {endOnIndex === 1 && (
                                <LocalizationProvider dateAdapter={AdapterDayjs}>
                                    <DatePicker
                                        label="End Date"
                                        value={endDate}
                                        onChange={(newDate) => {
                                            if (newDate) {
                                                const startDayJs = toDayJsDate(reminderData.startDate);
                                                if (newDate < startDayJs) {
                                                    setError({ state: true, message: "End date must be after start date" });
                                                    setReminderData({ ...reminderData, endDate: fromDayJsDate(startDayJs) });
                                                } else {
                                                    setError({ state: false, message: "" });
                                                    setEndDate(newDate);
                                                    setReminderData({ ...reminderData, endDate: fromDayJsDate(newDate) });
                                                }
                                            }
                                        }}
                                        slotProps={{
                                            textField: { fullWidth: true, sx: { mt: 2 } }
                                        }}
                                    />
                                </LocalizationProvider>
                            )}

                            {endOnIndex === 2 && (
                                <TextField
                                    type="number"
                                    label="Number of Occurrences"
                                    slotProps={{ htmlInput: { min: 1 } }}
                                    onChange={(e) => handleOccurrencesChange(e.target.value)}
                                    sx={{ mt: 2, width: 200 }}
                                    error={error.state}
                                    helperText={error.message}
                                />
                            )}

                            {weeklyEventsVisible && (
                                <Box sx={{ mt: 3, pt: 2, borderTop: '1px solid', borderColor: 'divider' }}>
                                    <Typography variant="subtitle2" sx={{ fontWeight: 600, mb: 2 }}>
                                        Repeat on
                                    </Typography>
                                    <FormGroup row>
                                        {checkBoxes.map((day) => (
                                            <FormControlLabel
                                                key={day.value}
                                                control={
                                                    <Checkbox
                                                        checked={reminderData.daysOfWeek.includes(day.value as dayOfWeekType)}
                                                        onChange={(e) => handleDaysOfWeekChange(day.value, e.target.checked)}
                                                    />
                                                }
                                                label={day.displayValue}
                                            />
                                        ))}
                                    </FormGroup>
                                </Box>
                            )}
                        </Box>
                    )}

                    {error.state && (
                        <FormHelperText error>
                            {error.message}
                        </FormHelperText>
                    )}
                </Box>
            </DialogContent>
            <DialogActions sx={{ p: 2, gap: 2 }}>
                <Button
                    variant="outlined"
                    onClick={() => handleClose(null)}
                    sx={{ flexShrink: 0 }}
                >
                    Cancel
                </Button>
                <Button
                    variant="contained"
                    onClick={handleSave}
                    sx={{ flexShrink: 0 }}
                >
                    Save
                </Button>
            </DialogActions>
        </Dialog>
    );
};

export default ReminderEditDialog;
